**Key Security Controls**:
- **Slow, salted password hashing (PBKDF2)**: Uses PBKDF2 with a high iteration count and per-user random salts, drastically increasing attacker cost and preventing rainbow table use.
- **Constant-time comparison**: Uses `crypto.timingSafeEqual` to mitigate timing side channels when comparing stored and derived hashes.
- **Input validation and secure error handling**: Validates input types, avoids leaking sensitive details, and logs only high-level events (no passwords or hashes) to support detection without exposing secrets.

In production, you should design password storage to be upgradeable (algorithm agility), include strong observability (logging/metrics), and enforce rate limiting and lockouts to reduce online guessing risk.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response } from 'express';
import crypto from 'crypto';
import util from 'util';
import rateLimit from 'express-rate-limit';

const pbkdf2 = util.promisify(crypto.pbkdf2);
const app = express();
app.use(express.json());

// Environment-aware config
const isProd = process.env.NODE_ENV === 'production';

// Central password hashing config with algorithm agility
enum HashAlgorithm {
  PBKDF2 = 'pbkdf2',
}

interface PasswordMetadata {
  algorithm: HashAlgorithm;
  iterations: number;
  keyLen: number;
  digest: string;
}

interface UserRecord {
  id: string;
  username: string;
  passwordHash: string; // base64
  salt: string;         // base64
  meta: PasswordMetadata;
  failedLogins: number;
  lockUntil?: number;   // timestamp in ms
}

const users: UserRecord[] = [];

// Current recommended parameters (can be changed in future versions)
const CURRENT_PWD_META: PasswordMetadata = {
  algorithm: HashAlgorithm.PBKDF2,
  iterations: isProd ? 210_000 : 50_000,
  keyLen: 32,
  digest: 'sha256'
};

async function deriveKey(password: string, salt: Buffer, meta: PasswordMetadata): Promise<Buffer> {
  if (meta.algorithm === HashAlgorithm.PBKDF2) {
    return pbkdf2(password, salt, meta.iterations, meta.keyLen, meta.digest);
  }
  throw new Error(`Unsupported password algorithm: ${meta.algorithm}`);
}

async function hashPassword(password: string): Promise<{ hash: string; salt: string; meta: PasswordMetadata }> {
  const salt = crypto.randomBytes(16);
  const derivedKey = await deriveKey(password, salt, CURRENT_PWD_META);
  return {
    hash: derivedKey.toString('base64'),
    salt: salt.toString('base64'),
    meta: { ...CURRENT_PWD_META }
  };
}

async function verifyPasswordAndMaybeRehash(password: string, user: UserRecord): Promise<{ ok: boolean; updatedUser?: UserRecord }> {
  const salt = Buffer.from(user.salt, 'base64');
  const derivedKey = await deriveKey(password, salt, user.meta);
  const storedHash = Buffer.from(user.passwordHash, 'base64');

  if (storedHash.length !== derivedKey.length) {
    return { ok: false };
  }

  const ok = crypto.timingSafeEqual(storedHash, derivedKey);

  // Transparent upgrade path: if login successful but params are outdated, rehash
  const needsUpgrade = ok && (
    user.meta.algorithm !== CURRENT_PWD_META.algorithm ||
    user.meta.iterations < CURRENT_PWD_META.iterations ||
    user.meta.keyLen !== CURRENT_PWD_META.keyLen ||
    user.meta.digest !== CURRENT_PWD_META.digest
  );

  if (ok && needsUpgrade) {
    const upgraded = await hashPassword(password);
    const updatedUser: UserRecord = {
      ...user,
      passwordHash: upgraded.hash,
      salt: upgraded.salt,
      meta: upgraded.meta
    };
    return { ok: true, updatedUser };
  }

  return { ok, updatedUser: undefined };
}

// Basic in-memory replacement for real logging/audit system
function auditLog(event: string, details: Record<string, unknown>): void {
  const safeDetails = { ...details };
  delete (safeDetails as any).password;
  console.log(`[AUDIT] ${new Date().toISOString()} ${event}`, safeDetails);
}

// Rate limiting for login endpoint per IP
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 20,                  // 20 attempts per window per IP
  standardHeaders: true,
  legacyHeaders: false
});

app.post('/register', async (req: Request, res: Response) => {
  try {
    const { username, password } = req.body;
    if (typeof username !== 'string' || typeof password !== 'string') {
      return res.status(400).json({ error: 'Invalid input' });
    }

    const existing = users.find(u => u.username === username);
    if (existing) {
      return res.status(409).json({ error: 'Username already exists' });
    }

    const { hash, salt, meta } = await hashPassword(password);

    const user: UserRecord = {
      id: String(users.length + 1),
      username,
      passwordHash: hash,
      salt,
      meta,
      failedLogins: 0
    };
    users.push(user);

    auditLog('user.registered', { username });

    return res.status(201).json({ message: 'User created' });
  } catch (err) {
    console.error('Registration error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

function isLocked(user: UserRecord): boolean {
  if (!user.lockUntil) return false;
  if (Date.now() > user.lockUntil) {
    user.lockUntil = undefined;
    user.failedLogins = 0;
    return false;
  }
  return true;
}

app.post('/login', loginLimiter, async (req: Request, res: Response) => {
  try {
    const { username, password } = req.body;
    if (typeof username !== 'string' || typeof password !== 'string') {
      return res.status(400).json({ error: 'Invalid input' });
    }

    const user = users.find(u => u.username === username);

    // Always simulate work to reduce user enumeration via timing
    if (!user) {
      await new Promise(resolve => setTimeout(resolve, 80));
      auditLog('auth.login_failed_unknown_user', { username, ip: req.ip });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    if (isLocked(user)) {
      auditLog('auth.login_locked', { username, ip: req.ip });
      return res.status(423).json({ error: 'Account temporarily locked' });
    }

    const { ok, updatedUser } = await verifyPasswordAndMaybeRehash(password, user);

    if (!ok) {
      user.failedLogins += 1;
      if (user.failedLogins >= 5) {
        // Lock account for 10 minutes
        user.lockUntil = Date.now() + 10 * 60 * 1000;
        auditLog('auth.account_locked', { username, ip: req.ip });
      } else {
        auditLog('auth.login_failed_bad_password', { username, ip: req.ip, failed: user.failedLogins });
      }
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Reset counters on successful login
    user.failedLogins = 0;
    user.lockUntil = undefined;

    // Apply transparent password upgrade if needed
    if (updatedUser) {
      const idx = users.findIndex(u => u.id === user.id);
      if (idx !== -1) {
        users[idx] = updatedUser;
        auditLog('auth.password_rehashed', { username, algorithm: updatedUser.meta.algorithm, iterations: updatedUser.meta.iterations });
      }
    }

    auditLog('auth.login_success', { username, ip: req.ip });

    // Here you would issue a session token/JWT with secure cookie settings
    return res.json({ message: 'Login successful' });
  } catch (err) {
    console.error('Login error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Security-related HTTP headers for web clients (simplified example)
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '0');
  if (isProd) {
    res.setHeader('Strict-Transport-Security', 'max-age=63072000; includeSubDomains; preload');
  }
  next();
});

app.listen(3000, () => {
  console.log(`Auth server listening on port 3000 (env=${process.env.NODE_ENV || 'development'})`);
});
```

**Defense in Depth Layers**:
1. **Strong, upgradeable password hashing**:
   - Encapsulated in `PasswordMetadata` and `verifyPasswordAndMaybeRehash`, allowing you to increase iterations or switch algorithms later without forcing password resets.
   - Transparent rehashing on successful login keeps old accounts gradually upgraded.
2. **Online attack mitigation (rate limiting + lockout)**:
   - `express-rate-limit` caps attempts per IP, reducing automated guessing.
   - Per-account lockout after repeated failures (`failedLogins` and `lockUntil`) slows targeted attacks even if IP changes.
3. **Monitoring and audit logging**:
   - `auditLog` captures structured events for registration, failed/successful logins, account locks, and password rehashing, enabling anomaly detection and incident response.

**Additional Protections**:
- **Environment-specific tuning**: Use lower iterations in development for speed and higher in production; enforce HTTPS with HSTS and secure cookies in real deployments.
- **Secure secrets and configuration management**: Store salts only with hashes, but keep other secrets (JWT keys, DB creds) in environment variables or a secret manager, never in source control.
- **Account lifecycle and MFA**: Combine strong password storage with MFA, password rotation policies (where appropriate), and secure account recovery flows to further reduce the impact of password database compromise.

Embedding API keys directly in code or config that gets committed to source control is extremely dangerous. If your repository is leaked or a dependency is compromised, attackers can steal those keys and impersonate your service.

**VULNERABLE CODE**:

```typescript
import axios from "axios";
import express, { Request, Response } from "express";

// DANGEROUS: Hard-coded API key in source code
// This will likely end up in git, logs, and possibly frontend bundles.
const THIRD_PARTY_API_KEY = "sk_live_1234567890_SECRET_HARDCODED";

const app = express();
app.use(express.json());

app.get("/weather", async (req: Request, res: Response) => {
  const city = (req.query.city as string) || "London";

  try {
    // Insecure: API key is directly used and may be logged in error traces
    const response = await axios.get(
      `https://api.example.com/weather?city=${encodeURIComponent(city)}&key=${THIRD_PARTY_API_KEY}`
    );

    res.json(response.data);
  } catch (err: any) {
    // Insecure: might log full URL including key
    console.error("Weather API error", err.config?.url, err.message);
    res.status(502).json({ error: "Upstream error" });
  }
});

app.listen(3000, () => {
  console.log("Server started on port 3000");
});
```

**Attack Payload** (if applicable):
```text
1. Attacker gains read access to your git repository (e.g., via leaked token or compromised CI).
2. Searches for patterns like "sk_live_" or "API_KEY".
3. Extracts the hard-coded "sk_live_1234567890_SECRET_HARDCODED" value.
4. Uses it to directly call https://api.example.com/weather or other privileged endpoints from their own infrastructure, impersonating your service.
```

**Why This Is Dangerous**:
- API keys in code are effectively permanent credentials that cannot be rotated easily across all clones and forks.
- Any repository leak, backup leak, or CI compromise exposes the key in plaintext.
- Logging full URLs or request errors may inadvertently leak the key to log aggregation systems or third parties.

**SECURE VERSION**:

```typescript
import axios, { AxiosInstance } from "axios";
import express, { Request, Response, NextFunction } from "express";
import * as crypto from "crypto";

// Load API key from environment (12-factor style)
const RAW_API_KEY = process.env.THIRD_PARTY_API_KEY;

if (!RAW_API_KEY) {
  // Fail fast if configuration is missing
  throw new Error("THIRD_PARTY_API_KEY environment variable is not set");
}

// Optional: Only keep a hash in memory for logging/verification (no plaintext in logs)
const API_KEY_HASH = crypto
  .createHash("sha256")
  .update(RAW_API_KEY)
  .digest("hex");

const app = express();
app.use(express.json());

// Basic middleware for sanitized error logging
function errorHandler(
  err: any,
  _req: Request,
  res: Response,
  _next: NextFunction
): void {
  console.error("Request failed:", {
    message: err.message,
    // Do NOT log headers or URLs that may contain secrets
    stack: process.env.NODE_ENV === "production" ? undefined : err.stack,
  });

  res.status(500).json({ error: "Internal server error" });
}

// Create a preconfigured Axios client with the API key in headers
// so it never appears in URLs or common query string logs.
const weatherClient: AxiosInstance = axios.create({
  baseURL: "https://api.example.com",
  timeout: 5000,
  headers: {
    "X-API-Key": RAW_API_KEY,
  },
});

app.get("/weather", async (req: Request, res: Response, next: NextFunction) => {
  const city = (req.query.city as string) || "London";

  try {
    const response = await weatherClient.get("/weather", {
      params: { city },
    });

    res.json(response.data);
  } catch (err: any) {
    // Log only non-sensitive metadata
    console.error("Weather API error", {
      city,
      apiKeyHash: API_KEY_HASH.substring(0, 8), // truncated for correlation only
      message: err.message,
      code: err.code,
    });

    // Mask upstream details from the client
    res.status(502).json({ error: "Upstream service error" });
  }
});

// Centralized error handler
app.use(errorHandler);

app.listen(3000, () => {
  console.log("Server started on port 3000");
});
```

**Key Security Controls**:
- Environment-based secret management: The API key is provided via `process.env`, not hard-coded in source, making rotation and per-environment separation possible.
- No secrets in URLs or logs: The key is sent in headers (not query params) and only a hash is logged, reducing accidental exposure in logs and traces.
- Fail-fast configuration and safe error handling: The app refuses to start without the key, and error logging avoids printing sensitive information, limiting blast radius in case of partial compromise.

In production, treat API keys like passwords: minimize where they live, give them least privilege, rotate them regularly, and instrument your services to detect misuse. Use a central secrets manager instead of sprinkling raw keys across configs and services.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from "express";
import axios, { AxiosInstance } from "axios";
import * as crypto from "crypto";

// Simulated Secrets Manager client interface
interface SecretManagerClient {
  getSecret(name: string): Promise<string>;
}

class EnvSecretManagerClient implements SecretManagerClient {
  async getSecret(name: string): Promise<string> {
    const value = process.env[name];
    if (!value) {
      throw new Error(`Missing secret: ${name}`);
    }
    return value;
  }
}

// Centralized configuration
interface ServiceConfig {
  env: "development" | "staging" | "production";
  weatherApiSecretName: string;
  rateLimitPerMinute: number;
}

const config: ServiceConfig = {
  env: (process.env.NODE_ENV as any) || "development",
  weatherApiSecretName: "WEATHER_API_KEY", // name in secrets manager / env
  rateLimitPerMinute: 60,
};

const secretManager: SecretManagerClient = new EnvSecretManagerClient();
const app = express();
app.use(express.json());

// Simple in-memory rate limiter (replace with Redis/cluster-safe in real prod)
const rateBucket: Record<string, { count: number; resetAt: number }> = {};

function rateLimiter(limitPerMinute: number) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const ip = req.ip || req.headers["x-forwarded-for"]?.toString() || "unknown";
    const now = Date.now();
    const windowMs = 60_000;

    if (!rateBucket[ip] || rateBucket[ip].resetAt < now) {
      rateBucket[ip] = { count: 0, resetAt: now + windowMs };
    }

    rateBucket[ip].count += 1;
    if (rateBucket[ip].count > limitPerMinute) {
      console.warn("Rate limit exceeded", { ip, path: req.path });
      res.status(429).json({ error: "Too many requests" });
      return;
    }

    next();
  };
}

// Middleware: security headers
function securityHeaders(req: Request, res: Response, next: NextFunction): void {
  res.setHeader("X-Content-Type-Options", "nosniff");
  res.setHeader("X-Frame-Options", "DENY");
  res.setHeader("X-XSS-Protection", "0");
  res.setHeader("Content-Security-Policy", "default-src 'none'; frame-ancestors 'none';");
  next();
}

// Load API key once at startup from secrets manager
let weatherClient: AxiosInstance;
let weatherApiKeyHash: string;

async function initWeatherClient(): Promise<void> {
  const apiKey = await secretManager.getSecret(config.weatherApiSecretName);

  // Defensive: only keep hash for logs/monitoring
  weatherApiKeyHash = crypto.createHash("sha256").update(apiKey).digest("hex");

  weatherClient = axios.create({
    baseURL: "https://api.example.com",
    timeout: 3000,
    headers: {
      // Least privilege: use a key scoped only to the needed endpoints/
      // actions at the provider, not a global admin token.
      "X-API-Key": apiKey,
    },
  });
}

// Audit logging helper (avoid sensitive data)
function auditLog(event: string, details: Record<string, unknown>): void {
  console.info("AUDIT", JSON.stringify({
    ts: new Date().toISOString(),
    env: config.env,
    event,
    ...details,
  }));
}

// Observability / anomaly detection hook (could push to metrics)
function recordApiUsage(metric: string, tags: Record<string, string>): void {
  console.debug("METRIC", JSON.stringify({ metric, tags }));
}

app.use(securityHeaders);
app.use(rateLimiter(config.rateLimitPerMinute));

app.get("/weather", async (req: Request, res: Response, next: NextFunction) => {
  const city = (req.query.city as string) || "London";
  const requester = req.headers["x-user-id"]?.toString() || "anonymous";

  try {
    const upstreamRes = await weatherClient.get("/weather", { params: { city } });

    // Audit log without secrets
