  key: fs.readFileSync(path.join(certDir, 'server-key.pem')),
  cert: fs.readFileSync(path.join(certDir, 'server-cert.pem')),

  // PRIMARY DEFENSE: Disable SSLv3, TLS 1.0, TLS 1.1
  secureProtocol: 'TLSv1_2_method',

  // PRIMARY DEFENSE: Restrict to strong ciphers only (no RC4, no 3DES)
  ciphers: [
    'TLS_AES_256_GCM_SHA384',
    'TLS_CHACHA20_POLY1305_SHA256',
    'TLS_AES_128_GCM_SHA256',
    'ECDHE-ECDSA-AES256-GCM-SHA384',
    'ECDHE-RSA-AES256-GCM-SHA384',
    'ECDHE-ECDSA-AES128-GCM-SHA256',
    'ECDHE-RSA-AES128-GCM-SHA256'
  ].join(':'),

  honorCipherOrder: true,
  // Optional: Disable renegotiation in newer Node versions when available
  // secureOptions.requestCert = false; // for mutual TLS change to true and configure CA
};

app.get('/login', (req: Request, res: Response) => {
  res.send('Secure login page over HTTPS with hardened TLS');
});

// SIMPLE ERROR HANDLER
app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
  console.error('Unexpected error:', err.message);
  res.status(500).send('Internal server error');
});

const port = Number(process.env.PORT) || 8443;
https.createServer(secureOptions, app).listen(port, () => {
  console.log(`Secure HTTPS server listening on port ${port}`);
});
