**Key Security Controls**:
- **Strong protocol and cipher selection**: Forces TLS 1.2+ and a curated list of strong ciphers, preventing downgrade attacks and blocking weak algorithms like RC4 or 3DES.
- **HSTS header (HTTP Strict-Transport-Security)**: Tells browsers to always use HTTPS for your domain, reducing the risk of SSL stripping attacks and accidental HTTP use.
- **Fail-safe error handling and logging**: Central error handler logs internal errors without leaking sensitive details to clients, supporting detection of misconfigurations or attacks.

For production you want a strict TLS profile, separate configs per environment, mutual TLS (mTLS) where appropriate, and strong observability so you can detect downgrade attempts and certificate issues.

**PRODUCTION PATTERN**:

```typescript
import https, { ServerOptions } from 'https';
import fs from 'fs';
import path from 'path';
import express, { Request, Response, NextFunction } from 'express';
import morgan from 'morgan';

// Simple structured logger wrapper
class Logger {
  static info(message: string, meta?: Record<string, unknown>): void {
    console.log(JSON.stringify({ level: 'info', message, ...meta }));
  }

  static error(message: string, meta?: Record<string, unknown>): void {
    console.error(JSON.stringify({ level: 'error', message, ...meta }));
  }
}

const app = express();

// REQUEST LOGGING (without sensitive data)
app.use(morgan('combined', {
  stream: {
    write: (msg: string) => Logger.info('http_request', { msg: msg.trim() })
  }
}));

// SECURITY HEADERS & RATE LIMITING (simplified example)
app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// Basic in-memory rate limiting for demo (use Redis/central store in real prod)
const requests: Record<string, { count: number; ts: number }> = {};
app.use((req: Request, res: Response, next: NextFunction) => {
  const key = req.ip || 'unknown';
  const now = Date.now();
  const windowMs = 60_000;
  const limit = 120; // 120 req/min demo limit

  if (!requests[key] || now - requests[key].ts > windowMs) {
    requests[key] = { count: 1, ts: now };
  } else {
    requests[key].count++;
  }

  if (requests[key].count > limit) {
    Logger.info('rate_limit_exceeded', { ip: key });
    return res.status(429).send('Too many requests');
  }

  next();
});

// ENV-SPECIFIC TLS SETTINGS
function buildTlsOptions(env: string): ServerOptions {
  const baseDir = process.env.TLS_CERT_DIR || path.join(__dirname, 'certs');

  const baseOptions: ServerOptions = {
    key: fs.readFileSync(path.join(baseDir, 'server-key.pem')),
    cert: fs.readFileSync(path.join(baseDir, 'server-cert.pem')),
    secureProtocol: 'TLSv1_2_method',
    ciphers: [
      'TLS_AES_256_GCM_SHA384',
      'TLS_CHACHA20_POLY1305_SHA256',
      'TLS_AES_128_GCM_SHA256',
      'ECDHE-ECDSA-AES256-GCM-SHA384',
      'ECDHE-RSA-AES256-GCM-SHA384',
      'ECDHE-ECDSA-AES128-GCM-SHA256',
      'ECDHE-RSA-AES128-GCM-SHA256'
    ].join(':'),
    honorCipherOrder: true,
    // Enable only secure renegotiation; Node handles this in modern versions
  };

  if (env === 'production') {
    // PRODUCTION: enable mutual TLS for specific internal APIs
    const caPath = process.env.TLS_CA_FILE || path.join(baseDir, 'ca-cert.pem');

    return {
      ...baseOptions,
      ca: fs.readFileSync(caPath),
      requestCert: true,
      rejectUnauthorized: true // CRITICAL: enforce client cert validation
    };
  }

  // DEV/TEST: allow self-signed server certs but keep strong ciphers
  return {
    ...baseOptions,
    requestCert: false,
    rejectUnauthorized: false // ONLY acceptable for local/dev; never for prod
  };
}

const env = process.env.NODE_ENV || 'development';
const tlsOptions = buildTlsOptions(env);

// HEALTHCHECK & BUSINESS ENDPOINTS
app.get('/healthz', (req: Request, res: Response) => {
  res.status(200).json({ status: 'ok', env });
});

app.get('/api/secure-data', (req: Request, res: Response) => {
  // In production with mTLS, inspect the certificate for authorization
  if (env === 'production') {
    const cert = (req.socket as any).getPeerCertificate?.();
    if (!cert || !cert.subject) {
      Logger.info('mtls_missing_or_invalid', { ip: req.ip });
      return res.status(401).send('Client certificate required');
    }
    // Example: simple CN check (in real systems use SANs and proper ACLs)
    const cn = cert.subject.CN;
    if (!cn || !cn.startsWith('trusted-client-')) {
      Logger.info('mtls_unauthorized_client', { ip: req.ip, cn });
      return res.status(403).send('Forbidden');
    }
  }

  res.json({ secret: 'sensitive-data-over-hardened-tls' });
});

// CENTRAL ERROR HANDLER
app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
  Logger.error('unhandled_error', { message: err.message, stack: err.stack });
  if (!res.headersSent) {
    res.status(500).send('Internal server error');
  }
});

const port = Number(process.env.PORT) || 8443;

try {
  const server = https.createServer(tlsOptions, app);

  // BASIC MONITORING HOOKS
  server.on('tlsClientError', (err, socket) => {
    Logger.error('tls_client_error', { message: err.message, remoteAddress: (socket as any).remoteAddress });
  });

  server.on('secureConnection', (tlsSocket) => {
    const protocol = tlsSocket.getProtocol();
    const cipher = tlsSocket.getCipher();
    Logger.info('tls_connection', { protocol, cipher });
  });

  server.listen(port, () => {
    Logger.info('https_server_started', { port, env });
  });
} catch (e) {
  const err = e as Error;
  Logger.error('https_server_start_failed', { message: err.message });
  // Graceful degradation: fail fast instead of running without TLS
  process.exit(1);
}
```

**Defense in Depth Layers**:
1. **Strict TLS configuration and mTLS**:
   - Strong ciphers and TLS 1.2+ only:
   ```typescript
   secureProtocol = 'TLSv1_2_method';
   ciphers = 'TLS_AES_256_GCM_SHA384:TLS_CHACHA20_POLY1305_SHA256:...';
   ```
   - Mutual TLS in production for internal APIs:
   ```typescript
   ca: fs.readFileSync(caPath),
   requestCert: true,
   rejectUnauthorized: true
   ```

2. **Application-layer authorization and rate limiting**:
   - Authorization tied to client certificate identity:
   ```typescript
   const cn = cert.subject.CN;
   if (!cn || !cn.startsWith('trusted-client-')) {
     return res.status(403).send('Forbidden');
   }
   ```
   - Simple rate limiting to reduce abuse and brute-force attempts:
   ```typescript
   if (requests[key].count > limit) {
     Logger.info('rate_limit_exceeded', { ip: key });
     return res.status(429).send('Too many requests');
   }
   ```

3. **Monitoring, logging, and graceful failure**:
   - TLS event logging to detect anomalies/downgrades:
   ```typescript
   server.on('secureConnection', (tlsSocket) => {
     const protocol = tlsSocket.getProtocol();
     const cipher = tlsSocket.getCipher();
     Logger.info('tls_connection', { protocol, cipher });
   });
   ```
   - Fail-fast on TLS startup errors:
   ```typescript
   } catch (e) {
     Logger.error('https_server_start_failed', { message: err.message });
     process.exit(1);
   }
   ```

**Additional Protections**:
- Use a managed certificate solution (e.g., AWS ACM, GCP Load Balancer, or an ingress controller) to terminate TLS with battle-tested defaults, then still require TLS between services where needed.
- Automate certificate rotation (server and client certs for mTLS) and monitor for impending expiry; expose a `/healthz` or metrics endpoint that reports certificate validity windows.
- Regularly audit your Node.js/OpenSSL versions and TLS configuration against current industry baselines (e.g., Mozilla Server Side TLS, OWASP ASVS) and run tools like SSL Labs or `testssl.sh` against your endpoints as part of CI/CD.

Hashing passwords with a single, fast hash like SHA-256 is dangerous because it makes brute-force and credential cracking far easier, especially if your user database is ever leaked.

**VULNERABLE CODE**:

```typescript
