interface User {
  id: number;
  username: string;
  // INSECURE: storing only a fast SHA-256 hash
  passwordHash: string;
}

const users: User[] = [];

function hashPasswordInsecure(password: string): string {
  // Fast, single round hash with no salt
  return crypto.createHash('sha256').update(password).digest('hex');
}

app.post('/register', (req: Request, res: Response) => {
  const { username, password } = req.body;
  const passwordHash = hashPasswordInsecure(password);

  const user: User = {
    id: users.length + 1,
    username,
    passwordHash
  };

  users.push(user);
  res.status(201).json({ message: 'User created' });
});

app.post('/login', (req: Request, res: Response) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username);
  if (!user) {
    return res.status(401).json({ message: 'Invalid credentials' });
  }

  const attemptedHash = hashPasswordInsecure(password);
  if (attemptedHash === user.passwordHash) {
    return res.json({ message: 'Logged in' });
  }

  res.status(401).json({ message: 'Invalid credentials' });
