// src/payment/ProdPaymentClient.ts
import axios, { AxiosInstance } from 'axios';
import { AppConfig } from '../config/Config';

interface RateState {
    windowStart: number;
    count: number;
}

export class ProdPaymentClient {
    private axiosClient: AxiosInstance;
    private cfg: AppConfig['payment'];
    private rateState: RateState = { windowStart: Date.now(), count: 0 };

    constructor(cfg: AppConfig['payment']) {
        this.cfg = cfg;
        this.axiosClient = axios.create({
            baseURL: this.cfg.baseUrl,
            timeout: this.cfg.timeoutMs,
        });
    }

    // Basic in-memory rate limiting per instance (add stronger solution in real prod)
    private enforceRateLimit(): void {
        const now = Date.now();
        const windowMs = 60_000; // 1 minute
        if (now - this.rateState.windowStart > windowMs) {
            this.rateState = { windowStart: now, count: 0 };
        }
        this.rateState.count++;
        if (this.rateState.count > this.cfg.rateLimitPerMinute) {
            throw new Error('Payment API rate limit exceeded');
        }
    }

    private getActiveApiKey(): string {
        // Simple rotation: prefer secondary if set, else primary
        return this.cfg.secondaryApiKey || this.cfg.primaryApiKey;
    }

    public async chargeCustomer(customerId: string, amountCents: number): Promise<void> {
        this.enforceRateLimit();

        if (!customerId || customerId.length > 128) {
            throw new Error('Invalid customerId');
        }
        if (!Number.isInteger(amountCents) || amountCents <= 0) {
            throw new Error('Invalid charge amount');
        }

        const apiKey = this.getActiveApiKey();

        try {
            const res = await this.axiosClient.post(
                '/charge',
                { customerId, amount: amountCents },
                {
                    headers: {
                        'Authorization': `Bearer ${apiKey}`,
                    },
                }
            );

            this.auditLog('payment.charge.success', {
                customerId,
                amountCents,
                status: res.status,
            });
        } catch (err: unknown) {
            if (axios.isAxiosError(err)) {
                const status = err.response?.status;
                this.securityLog('payment.charge.failure', {
                    code: err.code,
                    status,
                    path: err.config?.url,
                });

                // Example of basic anomaly detection trigger
                if (status === 401 || status === 403) {
                    this.securityLog('payment.api.unauthorized', {
                        message: 'Possible invalid or revoked API key',
                    });
                }
            } else {
                this.securityLog('payment.charge.error', {
                    message: 'Unexpected payment error type',
                });
            }

            throw new Error('Failed to process payment');
        }
    }

    private auditLog(event: string, data: Record<string, unknown>): void {
        // In real production, send to centralized audit log (e.g., SIEM)
        const payload = {
            ts: new Date().toISOString(),
            event,
            data,
        };
        fs.appendFile('logs/audit.log', JSON.stringify(payload) + '\n', () => { /* ignore */ });
    }

    private securityLog(event: string, data: Record<string, unknown>): void {
        const payload = {
            ts: new Date().toISOString(),
            severity: 'warn',
            event,
            data,
        };
        fs.appendFile('logs/security.log', JSON.stringify(payload) + '\n', () => { /* ignore */ });
    }
}

